type Result<T> =
  | { success: true; value: T }
  | { success: false; error: string };

function divide(a: number, b: number): Result<number> {
  if (b === 0) {
    return { success: false, error: 'Cannot divide by zero' };
  }
  return { success: true, value: a / b };
}

const result = divide(10, 0);

if (result.success) {
  console.log('Result:', result.value);
} else {
  console.error('Error:', result.error);
}

class Left<L> {
  readonly value: L;
  constructor(value: L) {
    this.value = value;
  }
  isLeft(): this is Left<L> { return true; }
  isRight(): this is Right<any> { return false; }
}

class Right<R> {
  readonly value: R;
  constructor(value: R) {
    this.value = value;
  }
  isLeft(): this is Left<any> { return false; }
  isRight(): this is Right<R> { return true; }
}

type Either<L, R> = Left<L> | Right<R>;

function parseNumber(str: string): Either<string, number> {
  const num = Number(str);
  if (isNaN(num)) {
    return new Left('Not a valid number');
  }
  return new Right(num);
}

const parseResult = parseNumber('123a');
if (parseResult.isRight()) {
  console.log('Parsed number:', parseResult.value);
} else {
  console.error('Parsing error:', parseResult.value);
}

